import{_ as t,o as e,c as o,a5 as a}from"./chunks/framework.B5tqjWbr.js";const L=JSON.parse('{"title":"学习记录 #0012：LLC谐振变换器原理与控制——UPS的DC-DC级","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0012：LLC谐振变换器原理与控制——UPS的DC-DC级","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第12课 — LLC谐振变换器（Phase 2核心拓扑） **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0012-llc-resonant-converter.md","filePath":"content/power/archive/old-learning-records/0012-llc-resonant-converter.md","lastUpdated":null}'),l={name:"content/power/archive/old-learning-records/0012-llc-resonant-converter.md"};function n(s,r,i,c,d,g){return e(),o("div",null,[...r[0]||(r[0]=[a('<h1 id="学习记录-0012-llc谐振变换器原理与控制——ups的dc-dc级" tabindex="-1">学习记录 #0012：LLC谐振变换器原理与控制——UPS的DC-DC级 <a class="header-anchor" href="#学习记录-0012-llc谐振变换器原理与控制——ups的dc-dc级" aria-label="Permalink to &quot;学习记录 #0012：LLC谐振变换器原理与控制——UPS的DC-DC级&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第12课 — LLC谐振变换器（Phase 2核心拓扑） <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>LLC在UPS中</strong>：隔离DC-DC，高压母线→电池电压，双向运行</li><li><strong>三个谐振元件</strong>：Lr（谐振电感）、Cr（谐振电容）、Lm（励磁电感）</li><li><strong>两个谐振频率</strong>：fr=1/(2π√(LrCr))（串联）、fp=1/(2π√((Lm+Lr)Cr))（并联）</li><li><strong>三种工作模式</strong>：欠谐振(fs&gt;fr,M&lt;1)、谐振点(fs=fr,M=1)、过谐振(fs&lt;fr,M&gt;1)</li><li><strong>必须工作在感性区</strong>：容性区=硬开关=器件损坏</li><li><strong>FHA增益曲线</strong>：Q越大曲线越陡，轻载Q→0曲线趋于水平</li><li><strong>ZVS条件</strong>：Im &gt; Coss×Vdc/tdead，轻载ZVS丢失是最常见问题</li><li><strong>PFM控制</strong>：fs↓→M↑→Vout↑（反比关系！），与PWM正比相反</li><li><strong>Burst Mode</strong>：轻载PFM失效时，间歇开关等效降低功率</li><li><strong>软启动</strong>：必须从高频扫到低频（M从低到高）</li></ol><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] 全桥LLC和半桥LLC有什么区别？</li><li>[ ] 双向LLC怎么做？充电和放电模式怎么切换？</li><li>[ ] LLC的环路补偿怎么设计？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第13课：双向DC-DC与电池管理</p>',8)])])}const h=t(l,[["render",n]]);export{L as __pageData,h as default};
